191â†’        vmax: Int,
192â†’    ): ArrayView {
193â†’        var r = arr.size - 1
194â†’        if (r == -1 || vmax < arr[0] || arr[r] < vmin) {
195â†’            return emptyArrayView
196â†’        }
197â†’        // binary search for min(arr[l] >= vmin)
198â†’        var l = 0
199â†’        while (l < r) {
200â†’            val m = (r + l) / 2
201â†’            if (vmax < arr[m]) {
202â†’                r = m - 1
203â†’            } else if (arr[m] < vmin) {
204â†’                l = m + 1
205â†’            } else {
206â†’                // arr[l] ?<=? vmin <= arr[m] <= vmax ?<=? arr[r]
207â†’                if (vmin <= arr[l]) break else l++ // optimization
208â†’                r = m
209â†’            }
210â†’        }
211â†’        if (l > r || arr[l] < vmin) {
212â†’            return emptyArrayView
213â†’        }
214â†’        // find max(k) such as arr[k] < vmax
215â†’        var k = l
216â†’        while (k < arr.size) {
217â†’            if (arr[k] >= vmax) {
218â†’                break
219â†’            }
220â†’            k++
221â†’        }
